-- Migration: gov — Round 70 A4 (splice): pre-2013 gov valuation index from the
-- master's own curated series. Project: government (scknotsqkcheojiaewwh). Live.
--
-- Scott: extend the index back toward 2000 via a documented splice -- "master's
-- own VI as the historical segment, source='master_curated', joined at the 2013
-- rebase point." Source data: scripts/gov_master_allcharts.json (branch
-- r69/master-index-data), 'Copy Government Master Document.xlsx / All Charts',
-- monthly Valuation Index + Avg.Rent / Expenses PSF / Average Cap Rate.
--
-- The master VI is its own NOI/cap index on a different absolute scale than our
-- gsa-computed index (different curated universe: master rent ~22.8 / cap ~8.2%
-- @2013 -> VI ~168; our gsa rent ~28.4 / cap ~7.4% -> VI ~276). The chart plots
-- the RAW valuation_index, so the master segment is scaled by a dynamically
-- computed k = avg(gsa VI 2013) / avg(master VI 2013) (~1.64) so the line is
-- CONTINUOUS at the 2013 join; k is recomputed in-view (no magic constant).
--
-- Architecture (so the gsa math stays in one place + the splice is a thin
-- wrapper): freeze the current gsa computation as cm_gov_valuation_index_gsa_m/
-- _q, seed the master series into cm_gov_valuation_index_master_curated, then
-- repoint cm_gov_valuation_index_m/_q at a UNION (master pre-2013 scaled +
-- gsa 2013+), re-deriving yoy + rebased across the join and appending a
-- 'source' column ('master_curated' | 'gsa_computed'). Future gsa-math changes
-- target cm_gov_valuation_index_gsa_m/_q.
--
-- Reach: monthly index now starts 1997-05 (was 2013) -- ~16 extra years.

-- 1. Freeze the current (post-A4 12mo/2013) gsa computation as base views.
DO $splice$
DECLARE d text;
BEGIN
  d := pg_get_viewdef('public.cm_gov_valuation_index_m'::regclass);
  EXECUTE 'CREATE OR REPLACE VIEW public.cm_gov_valuation_index_gsa_m AS ' || d;
  d := pg_get_viewdef('public.cm_gov_valuation_index_q'::regclass);
  EXECUTE 'CREATE OR REPLACE VIEW public.cm_gov_valuation_index_gsa_q AS ' || d;
END $splice$;

-- 2. Master-curated series table (idempotent seed, <= 2013-12 incl. overlap).
CREATE TABLE IF NOT EXISTS public.cm_gov_valuation_index_master_curated (
  period_end        date PRIMARY KEY,
  valuation_index   numeric,
  avg_rent_psf      numeric,
  avg_expenses_psf  numeric,
  avg_cap_rate      numeric,
  source            text NOT NULL DEFAULT 'master_curated'
);
TRUNCATE public.cm_gov_valuation_index_master_curated;

-- 3. Spliced monthly wrapper.
CREATE OR REPLACE VIEW public.cm_gov_valuation_index_m AS
WITH k AS (
  SELECT (SELECT avg(valuation_index) FROM cm_gov_valuation_index_gsa_m
            WHERE period_end BETWEEN '2013-01-01' AND '2013-12-31')
       / NULLIF((SELECT avg(valuation_index) FROM cm_gov_valuation_index_master_curated
            WHERE period_end BETWEEN '2013-01-01' AND '2013-12-31'),0) AS k
),
unified AS (
  SELECT mc.period_end, 'all'::text AS subspecialty, mc.avg_rent_psf, mc.avg_expenses_psf,
         (mc.avg_rent_psf - mc.avg_expenses_psf) AS avg_noi_psf, mc.avg_cap_rate,
         (mc.valuation_index * (SELECT k FROM k)) AS valuation_index,
         NULL::bigint AS ttm_n, NULL::bigint AS n_with_noi_ttm, NULL::bigint AS n_with_cap_ttm,
         'master_curated'::text AS source
  FROM cm_gov_valuation_index_master_curated mc
  WHERE mc.period_end < '2013-01-01'
  UNION ALL
  SELECT g.period_end, g.subspecialty, g.avg_rent_psf, g.avg_expenses_psf, g.avg_noi_psf,
         g.avg_cap_rate, g.valuation_index, g.ttm_n, g.n_with_noi_ttm, g.n_with_cap_ttm,
         'gsa_computed'::text AS source
  FROM cm_gov_valuation_index_gsa_m g
  WHERE g.valuation_index IS NOT NULL
)
SELECT period_end, subspecialty, avg_rent_psf, avg_expenses_psf, avg_noi_psf, avg_cap_rate,
       valuation_index, ttm_n, n_with_noi_ttm, n_with_cap_ttm,
       CASE WHEN lag(valuation_index,12) OVER w IS NOT NULL AND lag(valuation_index,12) OVER w <> 0
            THEN (valuation_index / lag(valuation_index,12) OVER w) - 1 ELSE NULL END AS yoy_change_pct,
       100 * valuation_index / NULLIF((SELECT u.valuation_index FROM unified u
              WHERE u.valuation_index IS NOT NULL ORDER BY u.period_end LIMIT 1),0) AS valuation_index_rebased,
       source
FROM unified
WINDOW w AS (ORDER BY period_end)
ORDER BY period_end;

-- 4. Spliced quarterly wrapper (master taken at quarter-end months).
CREATE OR REPLACE VIEW public.cm_gov_valuation_index_q AS
WITH kq AS (
  SELECT (SELECT avg(valuation_index) FROM cm_gov_valuation_index_gsa_q
            WHERE period_end BETWEEN '2013-01-01' AND '2013-12-31')
       / NULLIF((SELECT avg(mc.valuation_index) FROM cm_gov_valuation_index_master_curated mc
            WHERE mc.period_end BETWEEN '2013-01-01' AND '2013-12-31'
              AND EXTRACT(month FROM mc.period_end) IN (3,6,9,12)),0) AS k
),
unified AS (
  SELECT mc.period_end, mc.avg_rent_psf, mc.avg_expenses_psf,
         (mc.avg_rent_psf - mc.avg_expenses_psf) AS avg_noi_psf, mc.avg_cap_rate,
         (mc.valuation_index * (SELECT k FROM kq)) AS valuation_index,
         NULL::numeric AS q_rent_psf, NULL::numeric AS q_expenses_psf, NULL::numeric AS q_noi_psf,
         NULL::numeric AS q_cap_rate, NULL::bigint AS n_sales, NULL::bigint AS n_with_noi_ttm,
         NULL::bigint AS n_with_cap_ttm, 'master_curated'::text AS source
  FROM cm_gov_valuation_index_master_curated mc
  WHERE mc.period_end < '2013-01-01' AND EXTRACT(month FROM mc.period_end) IN (3,6,9,12)
  UNION ALL
  SELECT g.period_end, g.avg_rent_psf, g.avg_expenses_psf, g.avg_noi_psf, g.avg_cap_rate,
         g.valuation_index, g.q_rent_psf, g.q_expenses_psf, g.q_noi_psf, g.q_cap_rate,
         g.n_sales, g.n_with_noi_ttm, g.n_with_cap_ttm, 'gsa_computed'::text AS source
  FROM cm_gov_valuation_index_gsa_q g
  WHERE g.valuation_index IS NOT NULL
)
SELECT period_end, avg_rent_psf, avg_expenses_psf, avg_noi_psf, avg_cap_rate, valuation_index,
       q_rent_psf, q_expenses_psf, q_noi_psf, q_cap_rate, n_sales, n_with_noi_ttm, n_with_cap_ttm,
       CASE WHEN lag(valuation_index,4) OVER w IS NOT NULL AND lag(valuation_index,4) OVER w <> 0
            THEN (valuation_index / lag(valuation_index,4) OVER w) - 1 ELSE NULL END AS yoy_change,
       source
FROM unified
WINDOW w AS (ORDER BY period_end)
ORDER BY period_end;
